# Boolean operations and comparisons
x: int = 10
y: int = 20

# Comparisons
greater: bool = x > y
less: bool = x < y
equal: bool = x == y
not_equal: bool = x != y

# Logical operations
and_op: bool = True and False
or_op: bool = True or False
not_op: bool = not True

print("10 > 20:", greater)
print("10 < 20:", less)
print("10 == 20:", equal)
print("10 != 20:", not_equal)
print("True and False:", and_op)
print("True or False:", or_op)
print("not True:", not_op)
